    LANGUAGE plpgsql
    AS $$
BEGIN
    INSERT INTO ged.user_security_event (
        tenant_id,
        user_id,
        servidor_id,
        event_type,
        event_description,
        created_by,
        ip_address,
        user_agent,
        correlation_id,
        data
    )
    VALUES (
        p_tenant_id,
        p_user_id,
        p_servidor_id,
        p_event_type,
        p_event_description,
        p_created_by,
        p_ip_address,
        p_user_agent,
        p_correlation_id,
        p_data
    );

    BEGIN
        INSERT INTO ged.audit_log (
            tenant_id,
            user_id,
            action,
            entity_name,
            entity_id,
            summary,
            event_type,
