            'app_user',
            p_user_id,
            p_event_description,
            'SECURITY',
            true,
            jsonb_build_object(
                'event_type', p_event_type,
                'target_user_id', p_user_id,
                'servidor_id', p_servidor_id
            ) || COALESCE(p_data, '{}'::jsonb)
        );
    EXCEPTION
        WHEN OTHERS THEN
            NULL;
    END;
