    LANGUAGE plpgsql
    AS $$
DECLARE
  v_id uuid := gen_random_uuid();
  v_year int := EXTRACT(YEAR FROM now())::int;
  v_num bigint := nextval('ged.protocol_seq');
BEGIN
  INSERT INTO ged.protocol(id, tenant_id, number, year)
  VALUES (v_id, p_tenant, v_num, v_year);
  RETURN v_id;
END $$;


