 SELECT d.tenant_id,
    d.id AS document_id,
    d.code AS doc_code,
    d.title AS doc_title,
    d.disposition_status,
    d.disposition_case_id,
    d.disposition_at,
    d.classification_id,
    c.code AS class_code,
    c.name AS class_name,
    d.retention_due_at,
    d.retention_status
   FROM (ged.document d
     LEFT JOIN ged.classification_plan c ON (((c.tenant_id = d.tenant_id) AND (c.id = d.classification_id))));


