    document_id,
    id AS signature_id,
    status,
    status_details,
    signing_time
   FROM ged.document_signature
  WHERE (reg_status = 'A'::bpchar)
  ORDER BY tenant_id, document_id, signing_time DESC NULLS LAST, reg_date DESC;


